export interface CSVOptions {
  delimiter?: string;
  quoteChar?: string;
  lineSeparator?: string;
}

export interface CSVError {
  row: number;
  message: string;
}

export interface CSVResult {
  rows: Array<Record<string, unknown>>;
  headers: string[];
  errors: CSVError[];
  filter(predicate: (row: Record<string, unknown>) => boolean): Array<Record<string, unknown>>;
  sum(column: string): number;
  average(column: string): number;
  count(): number;
  groupBy(column: string): Map<unknown, Array<Record<string, unknown>>>;
}

const DEFAULT_DELIMITER = ",";
const DEFAULT_QUOTE = '"';
const DEFAULT_LINE_SEPARATOR = "\n";

const NUMBER_REGEX = /^-?\d+(?:\.\d+)?$/;

function normalizeInput(input: string, lineSeparator: string | undefined): { content: string; lineSeparator: string } {
  if (lineSeparator) {
    return { content: input, lineSeparator };
  }

  const normalized = input.replace(/\r\n/g, "\n").replace(/\r/g, "\n");
  return { content: normalized, lineSeparator: DEFAULT_LINE_SEPARATOR };
}

function coerceValue(value: string): unknown {
  const trimmed = value.trim();
  if (trimmed === "") {
    return null;
  }

  const lower = trimmed.toLowerCase();
  if (lower === "null") {
    return null;
  }

  if (lower === "true") {
    return true;
  }

  if (lower === "false") {
    return false;
  }

  if (NUMBER_REGEX.test(trimmed)) {
    return Number(trimmed);
  }

  return value;
}

function createResult(
  rows: Array<Record<string, unknown>>,
  headers: string[],
  errors: CSVError[]
): CSVResult {
  return {
    rows,
    headers,
    errors,
    filter: (predicate) => rows.filter(predicate),
    sum: (column: string) => {
      return rows.reduce((total, row) => {
        const value = row[column];
        if (typeof value === "number" && !Number.isNaN(value)) {
          return total + value;
        }
        return total;
      }, 0);
    },
    average: (column: string) => {
      let total = 0;
      let count = 0;
      for (const row of rows) {
        const value = row[column];
        if (typeof value === "number" && !Number.isNaN(value)) {
          total += value;
          count += 1;
        }
      }
      return count === 0 ? 0 : total / count;
    },
    count: () => rows.length,
    groupBy: (column: string) => {
      const grouped = new Map<unknown, Array<Record<string, unknown>>>();
      for (const row of rows) {
        const key = row[column];
        const bucket = grouped.get(key);
        if (bucket) {
          bucket.push(row);
        } else {
          grouped.set(key, [row]);
        }
      }
      return grouped;
    },
  };
}

export function parseCSV(input: string, options: CSVOptions = {}): CSVResult {
  const delimiter = options.delimiter ?? DEFAULT_DELIMITER;
  const quoteChar = options.quoteChar ?? DEFAULT_QUOTE;
  const normalized = normalizeInput(input, options.lineSeparator);
  const lineSeparator = normalized.lineSeparator;
  const content = normalized.content;

  const errors: CSVError[] = [];

  if (content.length === 0) {
    return createResult([], [], errors);
  }

  const rows: string[][] = [];
  const rowNumbers: number[] = [];

  let currentField = "";
  let currentRow: string[] = [];
  let inQuotes = false;
  let rowNumber = 1;
  let index = 0;

  const lineSeparatorLength = lineSeparator.length;

  const matchesLineSeparator = (position: number) => {
    return content.substr(position, lineSeparatorLength) === lineSeparator;
  };

  while (index < content.length) {
    const char = content[index];

    if (inQuotes) {
      if (char === quoteChar) {
        const nextChar = content[index + 1];
        if (nextChar === quoteChar) {
          currentField += quoteChar;
          index += 2;
          continue;
        }
        inQuotes = false;
        index += 1;
        continue;
      }
      currentField += char;
      index += 1;
      continue;
    }

    if (char === quoteChar && currentField === "") {
      inQuotes = true;
      index += 1;
      continue;
    }

    if (char === delimiter) {
      currentRow.push(currentField);
      currentField = "";
      index += 1;
      continue;
    }

    if (matchesLineSeparator(index)) {
      currentRow.push(currentField);
      rows.push(currentRow);
      rowNumbers.push(rowNumber);
      currentRow = [];
      currentField = "";
      rowNumber += 1;
      index += lineSeparatorLength;
      continue;
    }

    currentField += char;
    index += 1;
  }

  if (inQuotes) {
    errors.push({ row: rowNumber, message: "Unclosed quoted field." });
  }

  currentRow.push(currentField);
  rows.push(currentRow);
  rowNumbers.push(rowNumber);

  if (content.endsWith(lineSeparator)) {
    const lastRow = rows[rows.length - 1];
    if (lastRow.length === 1 && lastRow[0] === "") {
      rows.pop();
      rowNumbers.pop();
    }
  }

  if (rows.length === 0) {
    return createResult([], [], errors);
  }

  const headers = rows.shift() ?? [];
  rowNumbers.shift();

  const dataRows: Array<Record<string, unknown>> = [];

  rows.forEach((row, rowIndex) => {
    const actualRowNumber = rowNumbers[rowIndex] ?? rowIndex + 2;
    if (row.length !== headers.length) {
      errors.push({
        row: actualRowNumber,
        message: `Row has ${row.length} columns but expected ${headers.length}.`,
      });
    }

    const record: Record<string, unknown> = {};
    headers.forEach((header, columnIndex) => {
      const value = row[columnIndex] ?? "";
      record[header] = coerceValue(value);
    });
    dataRows.push(record);
  });

  return createResult(dataRows, headers, errors);
}

import { parseCSV } from "./csv-parser";

function assert(condition: boolean, message: string): void {
  if (!condition) {
    throw new Error(message);
  }
}

function assertEqual(actual: unknown, expected: unknown, message: string): void {
  const actualJson = JSON.stringify(actual);
  const expectedJson = JSON.stringify(expected);
  if (actualJson !== expectedJson) {
    throw new Error(`${message}\nExpected: ${expectedJson}\nActual:   ${actualJson}`);
  }
}

function runTest(name: string, test: () => void): void {
  try {
    test();
    console.log(`✓ ${name}`);
  } catch (error) {
    console.error(`✗ ${name}`);
    throw error;
  }
}

runTest("basic parsing", () => {
  const input = "name,age\nAlice,30\nBob,25";
  const result = parseCSV(input);
  assertEqual(result.headers, ["name", "age"], "Headers should match");
  assertEqual(result.rows.length, 2, "Should parse two rows");
  assertEqual(result.rows[0], { name: "Alice", age: 30 }, "First row should parse correctly");
  assertEqual(result.rows[1], { name: "Bob", age: 25 }, "Second row should parse correctly");
});

runTest("quoted fields with commas", () => {
  const input = "name,quote\nAlice,\"Hello, world\"\nBob,\"Another, value\"";
  const result = parseCSV(input);
  assertEqual(result.rows[0], { name: "Alice", quote: "Hello, world" }, "Quoted field should include comma");
  assertEqual(result.rows[1], { name: "Bob", quote: "Another, value" }, "Quoted field should include comma in second row");
});

runTest("escaped quotes", () => {
  const input = "name,quote\nAlice,\"He said \"\"Hi\"\"\"";
  const result = parseCSV(input);
  assertEqual(result.rows[0], { name: "Alice", quote: "He said \"Hi\"" }, "Escaped quotes should be unescaped");
});

runTest("custom delimiters and line separators", () => {
  const input = "name;age|Alice;30|Bob;25";
  const result = parseCSV(input, { delimiter: ";", lineSeparator: "|", quoteChar: "'" });
  assertEqual(result.headers, ["name", "age"], "Custom delimiter headers should parse");
  assertEqual(result.rows[0], { name: "Alice", age: 30 }, "Custom delimiter first row should parse");
  assertEqual(result.rows[1], { name: "Bob", age: 25 }, "Custom delimiter second row should parse");
});

runTest("type coercion", () => {
  const input = "int,float,bool,null,empty,string\n42,3.14,true,NULL,,hello";
  const result = parseCSV(input);
  assertEqual(
    result.rows[0],
    { int: 42, float: 3.14, bool: true, null: null, empty: null, string: "hello" },
    "Values should coerce to expected types"
  );
});

runTest("malformed row error collection", () => {
  const input = "a,b\n1\n2,3,4";
  const result = parseCSV(input);
  assertEqual(result.errors.length, 2, "Should collect two errors");
  assertEqual(result.errors[0].row, 2, "First error row number should be 2");
  assertEqual(result.errors[1].row, 3, "Second error row number should be 3");
  assertEqual(result.rows[0], { a: 1, b: null }, "Missing field should be null");
  assertEqual(result.rows[1], { a: 2, b: 3 }, "Extra field should be ignored beyond headers");
});

runTest("filter functionality", () => {
  const input = "name,age\nAlice,30\nBob,25\nCara,35";
  const result = parseCSV(input);
  const filtered = result.filter((row) => (row.age as number) > 29);
  assertEqual(filtered.length, 2, "Filter should return matching rows");
  assertEqual(filtered[0].name, "Alice", "Filtered row should include Alice");
  assertEqual(filtered[1].name, "Cara", "Filtered row should include Cara");
});

runTest("aggregation methods", () => {
  const input = "name,age,city\nAlice,30,NY\nBob,25,SF\nCara,35,NY";
  const result = parseCSV(input);
  assertEqual(result.count(), 3, "Count should return total rows");
  assertEqual(result.sum("age"), 90, "Sum should add numeric values");
  assertEqual(result.average("age"), 30, "Average should calculate mean");

  const grouped = result.groupBy("city");
  assertEqual(grouped.size, 2, "GroupBy should create two groups");
  assertEqual(grouped.get("NY")?.length, 2, "NY group should have two rows");
  assertEqual(grouped.get("SF")?.length, 1, "SF group should have one row");
});

runTest("edge case: empty input", () => {
  const result = parseCSV("");
  assertEqual(result.headers, [], "Empty input should produce no headers");
  assertEqual(result.rows, [], "Empty input should produce no rows");
  assertEqual(result.errors, [], "Empty input should produce no errors");
  assertEqual(result.count(), 0, "Count should be zero for empty input");
  assertEqual(result.sum("any"), 0, "Sum should be zero for empty input");
});

runTest("edge case: single column", () => {
  const input = "value\n1\n2\n3";
  const result = parseCSV(input);
  assertEqual(result.headers, ["value"], "Single column header should parse");
  assertEqual(result.rows.length, 3, "Should parse three rows");
  assertEqual(result.sum("value"), 6, "Sum should work for single column");
  assertEqual(result.average("value"), 2, "Average should work for single column");
});

runTest("edge case: single row", () => {
  const input = "a,b\n1,2";
  const result = parseCSV(input);
  assertEqual(result.rows.length, 1, "Should parse single row");
  assertEqual(result.rows[0], { a: 1, b: 2 }, "Single row should parse correctly");
});

runTest("edge case: large fields", () => {
  const largeValue = "x".repeat(10000);
  const input = `text\n\"${largeValue}\"`;
  const result = parseCSV(input);
  assertEqual(result.rows[0].text, largeValue, "Large field should parse correctly");
});

runTest("line separator normalization", () => {
  const input = "a,b\r\n1,2\r\n3,4";
  const result = parseCSV(input);
  assertEqual(result.rows.length, 2, "Should parse rows with CRLF separators");
  assertEqual(result.rows[1], { a: 3, b: 4 }, "CRLF row should parse correctly");
});

